            {viewOrd.status==="Approved"&&<div style={{background:"#fff8e1",borderRadius:12,padding:14,marginTop:14,border:"1px solid #ffe082"}}><div style={{fontWeight:800,fontSize:14,marginBottom:10,color:"#1a2a6c"}}>💳 Payment Details</div><div style={{fontSize:13,color:"#333",lineHeight:2.2}}><div>🏦 <b>Bank:</b> {B.bank.bank}</div><div>👤 <b>Name:</b> {B.bank.name}</div><div>🔢 <b>Acc No:</b> {B.bank.acc}</div><div>📍 <b>Branch:</b> {B.bank.branch}</div></div><div style={{marginTop:8,padding:"8px 12px",background:"#fff3cd",borderRadius:8,fontWeight:700,color:"#856404",fontSize:13}}>📝 Reference: {viewOrd.id}</div><div style={{fontSize:11,color:"#888",marginTop:6}}>Use order ID as reference. Delivery within 24hrs of payment.</div></div>}
