            {isAdmin&&viewOrd.status==="Approved"&&<button onClick={()=>{updStatus(viewOrd.id,"Delivered");setVO({...viewOrd,status:"Delivered"});showToast("📦 Delivered!");}} style={{width:"100%",padding:13,background:"#2e7d32",color:"#fff",border:"none",borderRadius:10,fontWeight:700,cursor:"pointer",marginTop:14}}>Mark as Delivered</button>}
